class n{constructor(t){this.runtime=t}setGravity(t,e=0){this.runtime.physics.setGravity(t,e)}setGravityEarth(){this.setGravity(1)}setGravityMoon(){this.setGravity(.16)}setGravityJupiter(){this.setGravity(2.53)}setZeroGravity(){this.setGravity(0)}setSimulationSpeed(t){const e=this.runtime.physics.getEngine();e.timing.timeScale=Math.max(0,Math.min(t,10))}getSimulationSpeed(){return this.runtime.physics.getEngine().timing.timeScale}setRestitution(t,e){const i=Math.max(0,Math.min(e,1));t.forEach(s=>{s.restitution=i})}setFriction(t,e){const i=Math.max(0,e);t.forEach(s=>{s.friction=i})}pause(){this.runtime.pause()}resume(){this.runtime.resume()}reset(){this.runtime.reset()}getState(){return this.runtime.getState()}}export{n as RuntimeControls};
